import React, { useState, useEffect, useRef } from 'react';

const AIChatbot = () => {
  const systemPrompt = `You are an expert in freelance client acquisition, proposal writing, pricing strategy (Indian ₹ market), tech stack advice, and client objection handling. Be conversational and helpful.`;
  const [conversation, setConversation] = useState([]);
  const [input, setInput] = useState('');
  const [streamingMessage, setStreamingMessage] = useState('');
  const [isStreaming, setIsStreaming] = useState(false);
  const [error, setError] = useState('');
  const scrollRef = useRef(null);

  const apiUrl = process.env.REACT_APP_API_URL || 'http://localhost:5000';

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollIntoView({ behavior: 'smooth', block: 'end' });
    }
  }, [conversation, streamingMessage]);

  const sendMessage = async () => {
    const trimmed = input.trim();
    if (!trimmed || isStreaming) return;

    setError('');
    const userMessage = { role: 'user', content: trimmed };
    setConversation((prev) => [...prev, userMessage]);
    setInput('');
    setStreamingMessage('');
    setIsStreaming(true);

    try {
      await streamAssistantResponse([...conversation, userMessage]);
    } catch (err) {
      setError(err.message || 'Something went wrong. Please try again.');
      setIsStreaming(false);
    }
  };

  const streamAssistantResponse = async (conversationPayload) => {
    const token = localStorage.getItem('token');
    const response = await fetch(`${apiUrl}/api/ai/chat`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: token ? `Bearer ${token}` : '',
      },
      body: JSON.stringify({ conversation: conversationPayload, systemPrompt }),
    });

    if (!response.ok) {
      const errorText = await response.text().catch(() => 'Unable to contact AI service.');
      throw new Error(errorText || 'AI service error');
    }

    const reader = response.body?.getReader();
    if (!reader) {
      throw new Error('Streaming response is not available.');
    }

    const decoder = new TextDecoder();
    let assistantText = '';
    let streamingStarted = false;

    while (true) {
      const { done, value } = await reader.read();
      if (done) break;
      const chunk = decoder.decode(value, { stream: true });
      for (const char of chunk) {
        assistantText += char;
        setStreamingMessage(assistantText);
      }
      if (!streamingStarted) {
        streamingStarted = true;
      }
    }

    setConversation((prev) => [...prev, { role: 'assistant', content: assistantText }]);
    setStreamingMessage('');
    setIsStreaming(false);
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    sendMessage();
  };

  const renderAssistantPreview = () => {
    if (isStreaming && streamingMessage.length === 0) {
      return (
        <div className="inline-flex items-center gap-2 rounded-3xl bg-slate-100 px-4 py-3 text-slate-600 shadow-sm">
          <span className="h-2 w-2 rounded-full bg-slate-500 animate-pulse" />
          <span>AI is typing</span>
        </div>
      );
    }

    if (streamingMessage.length > 0) {
      return (
        <div className="flex items-end gap-2 text-slate-900">
          <span>{streamingMessage}</span>
          <span className="animate-pulse text-slate-500">|</span>
        </div>
      );
    }

    return null;
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100">
      <div className="mx-auto flex min-h-screen max-w-[1500px] flex-col px-4 py-6 lg:grid lg:grid-cols-[300px_1fr] lg:gap-6">
        <aside className="hidden rounded-[32px] border border-slate-800 bg-slate-900 p-5 shadow-2xl lg:flex lg:flex-col">
          <div className="mb-6 flex items-center justify-between">
            <div>
              <p className="text-sm font-semibold uppercase tracking-[0.2em] text-slate-500">Chat</p>
              <h2 className="mt-2 text-2xl font-semibold text-white">AI Assistant</h2>
            </div>
            <div className="flex h-12 w-12 items-center justify-center rounded-2xl bg-slate-800 text-lg font-semibold text-cyan-300">AI</div>
          </div>

          <div className="space-y-3 overflow-y-auto pr-1">
            <button className="w-full rounded-3xl border border-slate-800 bg-slate-950 px-4 py-4 text-left text-sm text-slate-200 transition hover:border-cyan-500 hover:bg-slate-900">
              New conversation
            </button>
            <div className="rounded-3xl border border-slate-800 bg-slate-950 p-4 text-sm text-slate-400">
              <p className="font-semibold text-slate-100">Quick tips</p>
              <ul className="mt-3 space-y-2 text-xs leading-5 text-slate-400">
                <li>Ask for outreach, pricing, or lead strategy.</li>
                <li>Use short prompts for concise answers.</li>
                <li>Switch to specific client questions for best results.</li>
              </ul>
            </div>
          </div>
        </aside>

        <main className="flex min-h-[calc(100vh-48px)] flex-col rounded-[32px] bg-white shadow-2xl lg:overflow-hidden">
          <header className="border-b border-slate-200 px-6 py-5">
            <div className="flex items-center gap-4">
              <div className="flex h-12 w-12 items-center justify-center rounded-3xl bg-cyan-500 text-xl font-semibold text-white">🤖</div>
              <div>
                <p className="text-sm uppercase tracking-[0.2em] text-slate-400">CRM AI</p>
                <h1 className="mt-1 text-2xl font-semibold text-slate-950">Sales assistant</h1>
              </div>
            </div>
          </header>

          <div className="flex flex-1 flex-col overflow-hidden">
            <div className="flex-1 overflow-y-auto px-6 py-6">
              <div className="rounded-[28px] border border-slate-200 bg-slate-50 p-6 shadow-sm">
                <div className="space-y-6">
                  {conversation.length === 0 && (
                    <div className="rounded-3xl border border-dashed border-slate-200 bg-white/80 p-8 text-center text-slate-500 shadow-sm">
                      Start your chat with the AI assistant here.
                    </div>
                  )}

                  {conversation.map((message, index) => (
                    <div
                      key={`${message.role}-${index}`}
                      className={`flex ${message.role === 'user' ? 'justify-end' : 'justify-start'}`}
                    >
                      {message.role === 'assistant' && (
                        <div className="mr-3 mt-1 flex h-10 w-10 items-center justify-center rounded-2xl bg-cyan-500 text-sm font-semibold text-white shadow-sm">
                          AI
                        </div>
                      )}

                      <div
                        className={`max-w-[85%] rounded-3xl px-5 py-4 text-sm leading-6 shadow-sm transition duration-300 ease-out ${
                          message.role === 'user'
                            ? 'bg-sky-600 text-white shadow-sky-200'
                            : 'bg-slate-100 text-slate-900'
                        }`}
                      >
                        <div className="font-medium text-slate-700">
                          {message.role === 'user' ? 'You' : 'Assistant'}
                        </div>
                        <div className="mt-2 whitespace-pre-wrap">{message.content}</div>
                      </div>
                    </div>
                  ))}

                  {isStreaming && (
                    <div className="flex justify-start">
                      <div className="mr-3 mt-1 flex h-10 w-10 items-center justify-center rounded-2xl bg-cyan-500 text-sm font-semibold text-white shadow-sm">
                        AI
                      </div>
                      <div className="max-w-[85%] rounded-3xl bg-slate-100 px-5 py-4 text-sm leading-6 text-slate-900 shadow-sm transition-opacity duration-500 ease-out">
                        <div className="font-medium text-slate-700">Assistant</div>
                        <div className="mt-2 whitespace-pre-wrap">
                          {streamingMessage || (
                            <span className="inline-flex items-center gap-2 text-slate-500">
                              <span className="h-2 w-2 rounded-full bg-slate-500 animate-pulse" />
                              Typing...
                            </span>
                          )}
                          {streamingMessage && <span className="animate-pulse text-slate-500">|</span>}
                        </div>
                      </div>
                    </div>
                  )}

                  <div ref={scrollRef} />
                </div>
              </div>
            </div>

            <footer className="border-t border-slate-200 bg-slate-50 px-6 py-5">
              {error && (
                <div className="mb-4 rounded-3xl border border-rose-100 bg-rose-50 px-4 py-3 text-sm text-rose-700">
                  {error}
                </div>
              )}

              <form onSubmit={handleSubmit} className="flex flex-col gap-3 sm:flex-row">
                <label htmlFor="chat-input" className="sr-only">
                  Enter message
                </label>
                <input
                  id="chat-input"
                  value={input}
                  onChange={(event) => setInput(event.target.value)}
                  disabled={isStreaming}
                  placeholder="Ask your AI assistant anything..."
                  className="min-h-[54px] flex-1 rounded-3xl border border-slate-200 bg-white px-4 py-3 text-sm text-slate-900 shadow-sm outline-none transition focus:border-cyan-400 focus:ring-2 focus:ring-cyan-200"
                />
                <button
                  type="submit"
                  disabled={isStreaming || !input.trim()}
                  className="inline-flex min-h-[54px] items-center justify-center rounded-3xl bg-cyan-600 px-6 py-3 text-sm font-semibold text-white transition hover:bg-cyan-500 disabled:cursor-not-allowed disabled:bg-slate-300 disabled:text-slate-500"
                >
                  <span className="mr-2">Send</span>
                  <span className="text-lg">→</span>
                </button>
              </form>
            </footer>
          </div>
        </main>
      </div>
    </div>
  );
};

export default AIChatbot;
